import React, { useState, useEffect } from 'react';

function App() {
    const [currentUser, setCurrentUser] = useState(null);
    const [view, setView] = useState('dashboard');

    // Echte Daten aus der Datenbank
    const [projects, setProjects] = useState([]);
    const [tasks, setTasks] = useState([]);
    const [users, setUsers] = useState([]);
    const [selectedProject, setSelectedProject] = useState(null);

    // Formular-States
    const [newProject, setNewProject] = useState({ name: '', description: '' });
    const [newTask, setNewTask] = useState('');

    // 1. Lade alle User für den Login-Bildschirm
    useEffect(() => {
        fetch('http://localhost:8081/api/users')
        .then(res => res.json())
        .then(data => setUsers(data))
        .catch(err => console.error("Fehler beim Laden der User:", err));
    }, []);

    // 2. Lade Projekte, wenn jemand eingeloggt ist
    useEffect(() => {
        if (currentUser) {
            fetchProjects();
        }
    }, [currentUser]);

    const fetchProjects = () => {
        fetch('http://localhost:8081/api/projects')
        .then(res => res.json())
        .then(data => setProjects(data));
    };

    const fetchTasks = (projectId) => {
        fetch(`http://localhost:8081/api/tasks/project/${projectId}`)
        .then(res => res.json())
        .then(data => setTasks(data));
    };

    // --- AKTIONEN (Jetzt mit echten Backend-Aufrufen) ---

    const handleLogin = (user) => {
        setCurrentUser(user);
        setView('dashboard');
    };

    // FEHLER BEHOBEN: Sauberer Logout ohne Reload
    const handleLogout = () => {
        setCurrentUser(null);
        setSelectedProject(null);
    };

    // FEHLER BEHOBEN: Echtes Speichern von Projekten
    const createProject = (e) => {
        e.preventDefault();
        fetch('http://localhost:8081/api/projects', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name: newProject.name, description: newProject.description, status: 'ACTIVE' })
        }).then(() => {
            setNewProject({ name: '', description: '' });
            fetchProjects(); // Liste neu laden
        });
    };

    // Echtes Speichern von Aufgaben
    const createTask = (e) => {
        e.preventDefault();
        fetch('http://localhost:8081/api/tasks', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title: newTask, projectId: selectedProject.id, status: 'OPEN' })
        }).then(() => {
            setNewTask('');
            fetchTasks(selectedProject.id); // Tasks neu laden
        });
    };

    const calculateProgress = (projectId) => {
        const projectTasks = tasks.filter(t => t.projectId === projectId);
        if (projectTasks.length === 0) return 0;
        const doneTasks = projectTasks.filter(t => t.status === 'DONE').length;
        return Math.round((doneTasks / projectTasks.length) * 100);
    };

    const openProject = (project) => {
        setSelectedProject(project);
        fetchTasks(project.id);
    };

    // --- VIEWS ---
    if (!currentUser) {
        return (
            <div style={styles.loginScreen}>
            <div style={styles.loginCard}>
            <div style={styles.logo}>✦ Nexus<span style={{fontWeight: 300}}>Task</span></div>
            <p style={{color: '#718096', marginBottom: '30px'}}>Wer bist du?</p>
            {users.map(u => (
                <button key={u.id} onClick={() => handleLogin(u)} style={styles.loginBtn}>
                Einloggen als {u.username} ({u.role})
                </button>
            ))}
            </div>
            </div>
        );
    }

    if (selectedProject) {
        const progress = calculateProgress(selectedProject.id);
        return (
            <DashboardLayout user={currentUser} logout={handleLogout}>
            <button onClick={() => setSelectedProject(null)} style={styles.btnBack}>← Zurück</button>
            <h2 style={styles.pageTitle}>{selectedProject.name}</h2>
            <div style={{height: '8px', background: '#edf2f7', borderRadius: '4px', marginBottom: '20px'}}>
            <div style={{height: '100%', background: '#48bb78', width: `${progress}%`, transition: '0.5s'}}></div>
            </div>

            <form onSubmit={createTask} style={styles.formRow}>
            <input style={styles.input} placeholder="Neue Aufgabe..." value={newTask} onChange={e => setNewTask(e.target.value)} required/>
            <button style={styles.btnPrimary}>Hinzufügen</button>
            </form>

            <div style={{marginTop: '20px'}}>
            {tasks.map(t => (
                <div key={t.id} style={styles.taskCard}>
                <strong>{t.title}</strong> - Status: {t.status}
                </div>
            ))}
            </div>
            </DashboardLayout>
        );
    }

    return (
        <DashboardLayout user={currentUser} logout={handleLogout}>
        <h2 style={styles.pageTitle}>Dashboard</h2>

        {currentUser.role === 'MANAGER' && (
            <div style={styles.glassCard}>
            <h3>Neues Projekt anlegen</h3>
            <form onSubmit={createProject} style={styles.formRow}>
            <input style={styles.input} placeholder="Name" value={newProject.name} onChange={e => setNewProject({...newProject, name: e.target.value})} required/>
            <input style={styles.input} placeholder="Beschreibung" value={newProject.description} onChange={e => setNewProject({...newProject, description: e.target.value})} required/>
            <button style={styles.btnPrimary}>Speichern</button>
            </form>
            </div>
        )}

        <div style={styles.projectGrid}>
        {projects.map(p => (
            <div key={p.id} style={styles.projectCard}>
            <h3>{p.name}</h3>
            <p>{p.description}</p>
            <button onClick={() => openProject(p)} style={styles.btnSecondaryFull}>Öffnen</button>
            </div>
        ))}
        </div>
        </DashboardLayout>
    );
}

// Layout-Komponente (unverändert)
const DashboardLayout = ({ user, logout, children }) => (
    <div style={styles.appLayout}>
    <aside style={styles.sidebar}>
    <div style={styles.sidebarLogo}>✦ NexusTask</div>
    <div style={styles.userInfo}>Angemeldet als:<br/><strong>{user.username}</strong></div>
    <button onClick={logout} style={styles.btnLogout}>Abmelden</button>
    </aside>
    <main style={styles.mainContent}>{children}</main>
    </div>
);

const styles = {
    loginScreen: { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', backgroundColor: '#f7fafc' },
    loginCard: { backgroundColor: '#fff', padding: '50px', borderRadius: '16px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', width: '400px', textAlign: 'center' },
    logo: { fontSize: '28px', fontWeight: 'bold', color: '#2b6cb0', marginBottom: '10px' },
    loginBtn: { display: 'block', width: '100%', padding: '12px', margin: '10px 0', backgroundColor: '#edf2f7', border: '1px solid #e2e8f0', borderRadius: '8px', cursor: 'pointer' },
    appLayout: { display: 'flex', height: '100vh', backgroundColor: '#f7fafc', fontFamily: 'sans-serif' },
    sidebar: { width: '250px', backgroundColor: '#1a202c', color: '#fff', padding: '20px', display: 'flex', flexDirection: 'column' },
    sidebarLogo: { fontSize: '24px', fontWeight: 'bold', marginBottom: '40px', color: '#63b3ed' },
